import { useState } from "react";
import Btn from "../components/ui/Btn";

const AssignModal = ({ student, rooms, onConfirm, onClose }) => {
  const [roomId, setRoomId] = useState("");
  const availableRooms = rooms.filter(r => r.occupants.length < r.capacity);

  return (
    <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.5)", display: "flex", alignItems: "center", justifyContent: "center", zIndex: 1000 }}>
      <div style={{ background: "#fff", borderRadius: 16, padding: 28, maxWidth: 420, width: "90%", boxShadow: "0 8px 32px rgba(0,0,0,0.2)" }}>
        <h3 style={{ margin: "0 0 16px", color: "#1e293b" }}>Assign Room to {student?.name}</h3>
        <select value={roomId} onChange={e => setRoomId(e.target.value)} style={{ width: "100%", padding: "10px 14px", borderRadius: 10, border: "1.5px solid #e2e8f0", fontSize: 14, outline: "none", fontFamily: "inherit", marginBottom: 20 }}>
          <option value="">Select a room</option>
          {availableRooms.map(r => (
            <option key={r.id} value={r.id}>{r.id} - {r.type} ({r.capacity - r.occupants.length} slots free)</option>
          ))}
        </select>
        <div style={{ display: "flex", gap: 10, justifyContent: "flex-end" }}>
          <Btn variant="ghost" onClick={onClose}>Cancel</Btn>
          <Btn onClick={() => roomId && onConfirm(student.id, roomId)} disabled={!roomId}>Confirm</Btn>
        </div>
      </div>
    </div>
  );
};

export default AssignModal;
